     5→  const SafetyException(super.message, {required super.code});
     6→}
     7→
     8→/// Trusted Contact Exceptions
     9→
    10→/// Exception thrown when a trusted contact is not found
    11→class TrustedContactNotFoundException extends SafetyException {
