    18→  /// Saves authentication tokens and expiration
    19→  Future<void> saveAuthData(
    20→    String token,
    21→    String refreshToken, {
    22→    DateTime? expiresAt,
    23→    String? idToken,
    24→  });
    25→
    26→  /// Retrieves the stored authentication token
    27→  Future<String?> getAuthToken();
    28→
    29→  /// Retrieves the stored ID token
    30→  Future<String?> getIdToken();
