   197→  void _handleRequestError(String endpoint, dynamic error) {
   198→    if (error is DioException) {
   199→      _networkMonitor.trackRequestAndResponse(
   200→        path: endpoint,
   201→        duration: Duration.zero,
   202→        statusCode: error.response?.statusCode ?? 0,
   203→        responseSize: _calculateResponseSize(error.response),
   204→        isError: true,
   205→        errorMessage: error.message,
   206→      );
   207→    } else {
   208→      _networkMonitor.trackRequestAndResponse(
   209→        path: endpoint,
   210→        duration: Duration.zero,
   211→        statusCode: 0,
   212→        responseSize: 0,
   213→        isError: true,
   214→        errorMessage: error.toString(),
   215→      );
   216→    }
   217→  }
   218→
   219→  /// Calculate the size of the response in bytes
   220→  int _calculateResponseSize(Response? response) {
   221→    if (response == null) return 0;
   222→
   223→    int size = 0;
   224→
   225→    // Add headers size
   226→    response.headers.forEach((name, values) {
   227→      size += name.length;
   228→      for (final value in values) {
   229→        size += value.length;
   230→      }
   231→    });
   232→
   233→    // Add data size
   234→    if (response.data is String) {
   235→      size += (response.data as String).length;
   236→    } else if (response.data is List<int>) {
   237→      size += (response.data as List<int>).length;
   238→    } else if (response.data != null) {
   239→      size += response.data.toString().length;
   240→    }
   241→
   242→    return size;
   243→  }
   244→}
